mapper.select:
      SELECT s.snum AS surveyNum,s.mnum AS sruveyMnum,s.sub AS surveySub,s.code AS surveyCode,s.sdate AS surveyDate,
      s.fin AS surveyFin,sc.surveytype AS surveytype,sc.subcode AS subCode,sc.surveytitle AS surveytitle,sc.surveycnt AS surveycnt
	  FROM SURVEY s, SURVEYCONTENT sc WHERE s.snum = sc.SUBCODE AND s.snum = #{snum}
